package com.hospital.management.controller.appointment;import com.hospital.management.model.*;import com.hospital.management.service.*;import org.junit.jupiter.api.Test;import javax.servlet.http.*;import java.io.*;import java.time.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;
class AppointmentServletTest {@Test void slotsReturnsJson()throws Exception{AppointmentService s=mock(AppointmentService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);StringWriter out=new StringWriter();when(q.getParameter("doctorId")).thenReturn("2");when(q.getParameter("appointmentDate")).thenReturn(LocalDate.now().plusDays(1).toString());when(r.getWriter()).thenReturn(new PrintWriter(out));when(s.getAvailableSlots(eq(2L),any(),isNull(),isNull())).thenReturn(List.of(new AvailableSlot(LocalTime.of(9,0),LocalTime.of(9,30),30)));new AvailableSlotsServlet(s).doGet(q,r);assertEquals("[{\"startTime\":\"09:00\",\"endTime\":\"09:30\",\"durationMinutes\":30}]",out.toString());verify(r).setContentType("application/json");}@Test void statusGetDoesNotMutate()throws Exception{AppointmentService s=mock(AppointmentService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);new AppointmentStatusServlet(s).doGet(q,r);verify(r).sendError(405);verifyNoInteractions(s);}@Test void invalidStatusActionIsRejected()throws Exception{AppointmentService s=mock(AppointmentService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);when(q.getParameter("appointmentId")).thenReturn("1");when(q.getParameter("action")).thenReturn("delete");new AppointmentStatusServlet(s).doPost(q,r);verify(r).sendError(400);verifyNoInteractions(s);}}
